--- 方块小游戏怪物对象数据

local math = math

---@class LBlockMiniGameObjData
local LBlockMiniGameObjData = LxClass("LBlockMiniGameObjData", nil)

--
function LBlockMiniGameObjData:LBlockMiniGameObjData(monsterRefId)
    self._model = gModelBlockMiniGame

    -- 怪物配置
    local monsterRef = self._model:GetMonsterRef(monsterRefId)
    self._monsterRef = monsterRef

    -- 普攻技能配置
    local comSkillRef = self._model:GetSkillRef(self._monsterRef.atkSkill)
    self._comSkillRef = comSkillRef

    -- 特殊技能技能配置
    local speSkillRef = self._model:GetSkillRef(self._monsterRef.skill)
    self._speSkillRef = speSkillRef


    -- 战斗相关属性
    self._attrMap = {}
    self._attrMap["hp"] = monsterRef.hp
    self._attrMap["maxHp"] = self._attrMap["hp"]
    self._attrMap["atk"] = monsterRef.atk
    self._attrMap["def"] = monsterRef.def
    self._attrMap["crt"] = monsterRef.crt
    self._attrMap["atkRange"] = (monsterRef.atkRange + 1) ^ 2  -- 方便计算两者距离时，不用开方
    self._attrMap["atkSpeed"] = monsterRef.atkSpeed

    -- buff血量
    self._buffHp = 0
end

-- 销毁
function LBlockMiniGameObjData:Destroy()
end

-- 获取怪物的配置
function LBlockMiniGameObjData:GetMonsterRef()
    return self._monsterRef
end

-- 获取普通技能配置
function LBlockMiniGameObjData:GetComSkillRef()
    return self._comSkillRef
end

-- 获取特殊技能配置
function LBlockMiniGameObjData:GetSpeSkillRef()
    return self._speSkillRef
end

-- 获取攻击距离
function LBlockMiniGameObjData:GetAtkDis()
    -- return self._attrMap["atkRange"]
    return self._attrMap.atkRange
end

-- 死亡
function LBlockMiniGameObjData:IsDead()
    return self:GetCurHp() <= 0
end

-- 设置当前血量
function LBlockMiniGameObjData:SetCurHp(hp)
    local buffHp = self._buffHp
    if self._buffHp > 0 then
        self._buffHp = self._buffHp - hp
    end

    if self._buffHp > 0 then
        return
    else
        hp = hp - buffHp
        self._buffHp = 0
    end

    self._attrMap.hp = hp
end

-- 获取当前血量
function LBlockMiniGameObjData:GetCurHp()
    return self._attrMap.hp + self._buffHp
end

-- 获取最大血量
function LBlockMiniGameObjData:GetMaxHp()
    return self._attrMap.maxHp + self._buffHp
end

-- 设置buff血量
function LBlockMiniGameObjData:SetBuffHp(hp)
    self._buffHp = hp
end

-- 获取属性
function LBlockMiniGameObjData:GetAttr(key)
    return self._attrMap[key]
end

-- 设置属性
function LBlockMiniGameObjData:SetAttr(key, value)
    self._attrMap[key] = value
end

-- 是否暴击
function LBlockMiniGameObjData:IsCrit()
    local rand = math.random(1, 10000)
    -- return rand <= self:GetAttr("crt")
    return rand <= self._attrMap.crt
end

-- 计算攻击伤害
function LBlockMiniGameObjData:CalculateAtkHurt(isSkill, targetObjData)
    local isCrit = self:IsCrit()
    local crit = isCrit and 1.5 or 1

    local per
    if isSkill then
        -- 技能
        per = self._monsterRef.skillCoefficient
    else
        -- 普攻
        per = self._monsterRef.atkCoefficient
    end
    -- local hurt = (self:GetAttr("atk") - targetObjData:GetAttr("def")) * per * crit
    local hurt = (self._attrMap.atk - targetObjData._attrMap.def) * per * crit
    hurt = math.floor(hurt)

    return hurt, isCrit
end

return LBlockMiniGameObjData
